const revenueData = $('Supabase → Revenue Data').first().json;
const report = $input.first().json.content?.[0]?.text || 'No report generated';
const period = $('Called by Agent').first().json.period || $('Called by Agent').first().json.parameters?.period || 'weekly';

return [{ json: {
  status: 'completed',
  workflow: '05_finance_revenue_report',
  period,
  data_summary: {
    total_income: revenueData.total_income || 0,
    total_expense: revenueData.total_expense || 0,
    net_revenue: revenueData.net_revenue || 0,
    transaction_count: revenueData.transaction_count || 0,
    by_type: revenueData.by_type || {},
    by_city: revenueData.by_city || {},
    by_currency: revenueData.by_currency || {}
  },
  report,
  completedAt: new Date().toISOString()
} }];
